import{_ as o,o as r,c as e,a2 as s}from"./chunks/framework.DvFsUg-r.js";const d=JSON.parse('{"title":"메인 화면 최근 글 목록 + 블로그 제목 변경","description":"","frontmatter":{"title":"메인 화면 최근 글 목록 + 블로그 제목 변경","feature_id":"010","status":"done","created":"2026-06-03 06:46 (KST)","date":"2026-06-03T00:00:00.000Z","tags":["vitepress","home","content-loader","ux"]},"headers":[],"relativePath":"specs/010-home-recent-posts/spec.md","filePath":"specs/010-home-recent-posts/spec.md","lastUpdated":null}'),n={name:"specs/010-home-recent-posts/spec.md"};function i(a,t,l,g,c,h){return r(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="spec-메인-화면-최근-글-목록-블로그-제목-변경" tabindex="-1">Spec: 메인 화면 최근 글 목록 + 블로그 제목 변경 <a class="header-anchor" href="#spec-메인-화면-최근-글-목록-블로그-제목-변경" aria-label="Permalink to &quot;Spec: 메인 화면 최근 글 목록 + 블로그 제목 변경&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>현재 메인 화면(<code>blog/index.md</code>)은 VitePress <code>layout: home</code> 의 <strong>hero + 고정 6개 기능 카드</strong>로만 구성된다. 카드는 섹션 진입점(개요·저널·명세·스킬 강연·Cowork·Hermes)을 안내할 뿐, <strong>실제로 어떤 글이 새로 올라왔는지</strong> 첫 화면에서 알 수 없다. 방문자는 무엇이 최신인지 보려면 저널/섹션으로 따로 들어가야 한다.</p><p>또한 사이트 제목이 &quot;Agent 설계 저널&quot; 인데, 운영자는 이를 <strong>&quot;Agent 개발방법&quot;</strong> 으로 바꾸고자 한다.</p><p>목적은 메인 화면에서 <strong>최근 글을 한눈에</strong> 보여주어(이미지가 있으면 대표 이미지와 함께) 방문자가 첫 화면에서 바로 최신 콘텐츠로 진입하게 하고, 브랜드 제목을 새 이름으로 통일하는 것이다.</p><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-06-03" tabindex="-1">Session 2026-06-03 <a class="header-anchor" href="#session-2026-06-03" aria-label="Permalink to &quot;Session 2026-06-03&quot;">​</a></h3><ul><li>Q: 메인 최근 글 목록의 &quot;주요 글&quot; 범위는? → A: <strong>전 섹션 통합</strong>(여러 섹션의 최근 글을 통합 나열). <ul><li><strong>정정(2026-06-03, analyze F1)</strong>: 최신순 정렬은 날짜가 전제이므로, 실제 통합 대상은 <strong>frontmatter 날짜(<code>date</code>/<code>created</code>)가 있는 섹션</strong> — 저널·명세 (spec.md)·Blog Archive 다. <strong>Cowork·Hermes·스킬 강연</strong>은 frontmatter 날짜가 없어(본문 텍스트에만 존재) <strong>현재 제외</strong>되며, 해당 섹션에 날짜를 추가하면 자동 편입된다(별도 후속 과제).</li></ul></li><li>Q: 대표 이미지 출처는? → A: <strong>frontmatter <code>image</code> 필드 우선, 없으면 본문 첫 이미지 자동 추출</strong>(폴백).</li><li>Q: 기능 카드와 최근 글 목록 배치는? → A: 기존 hero+6카드 <strong>유지</strong>하고 그 <strong>아래에 최근 글 목록</strong> 추가.</li><li>Q: 목록 항목 요약은? → A: frontmatter 요약(<code>description</code> 등) <strong>필드 우선, 없으면 본문 앞부분 발췌</strong>.</li></ul><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><h3 id="포함" tabindex="-1">포함 <a class="header-anchor" href="#포함" aria-label="Permalink to &quot;포함&quot;">​</a></h3><ul><li>메인 화면에 <strong>주요 글 목록을 최신(생성/작성일) 내림차순</strong>으로 노출.</li><li>각 글 항목에 <strong>제목 + 요약(또는 발췌) + 날짜</strong> 표시.</li><li><strong>이미지가 있는 글</strong>은 대표 이미지를 항목에 함께 표시. 없는 글은 이미지 없이(또는 일관된 자리표시 없이) 표시.</li><li><strong>블로그 제목을 &quot;Agent 개발방법&quot;</strong> 으로 변경(사이트 타이틀 및 메인 hero).</li><li>새 글이 추가되면 메인 목록에 <strong>자동 반영</strong>(수동 편집 불필요).</li></ul><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li>글 본문 작성·수정, 카테고리/태그 페이지 신설.</li><li>이미지 업로드 도구·이미지 편집 기능.</li><li>댓글·좋아요·조회수 등 상호작용 기능.</li><li>검색 기능 변경, 사이드바/상단 메뉴 구조 변경(009 에서 다룸).</li><li>무한 스크롤·페이지네이션 등 대량 목록 UX(초기엔 상위 N개만).</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>첫 방문자</strong>: 메인 화면에 들어오면, 가장 최근 글이 맨 위에 오는 목록을 보고 &quot;이 블로그가 최근 무엇을 다뤘는지&quot; 즉시 파악한다.</li><li><strong>이미지가 있는 글 탐색</strong>: 대표 이미지가 붙은 글은 목록에서 시각적으로 먼저 눈에 들어와, 관심 가는 글을 빠르게 고른다.</li><li><strong>재방문자</strong>: 며칠 만에 다시 와서, 맨 위 몇 개만 보고 새 글이 올라왔는지 바로 확인한다.</li><li><strong>운영자(저자)</strong>: 새 글을 추가하면 별도 작업 없이 메인 목록 맨 위에 자동으로 노출된다. 글에 대표 이미지를 지정하면 목록에 그 이미지가 함께 나온다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="메인-글-목록" tabindex="-1">메인 글 목록 <a class="header-anchor" href="#메인-글-목록" aria-label="Permalink to &quot;메인 글 목록&quot;">​</a></h3><ul><li><strong>FR-1</strong>: 메인 화면은 <strong>frontmatter 날짜(<code>date</code>/<code>created</code>)가 있는 섹션 (저널·명세 spec.md·Blog Archive)을 통합</strong>한 주요 글 목록을 <strong>최신 날짜 내림차순</strong>으로 노출한다(가장 최근 글이 맨 위). 날짜 메타데이터가 없는 글 (Cowork·Hermes·스킬 강연 등)은 <strong>목록에서 제외</strong>한다(렌더링 실패 금지). 날짜를 추가하면 자동 편입된다.</li><li><strong>FR-2</strong>: 각 목록 항목은 <strong>제목·요약·날짜</strong>를 포함한다. 클릭하면 해당 글로 이동한다.</li><li><strong>FR-3</strong>: 대표 이미지는 <strong>frontmatter <code>image</code> 필드를 우선</strong> 사용하고, 없으면 <strong>본문 첫 이미지를 자동 추출</strong>해 항목에 함께 표시한다. 둘 다 없으면 이미지 영역 없이 표시한다(레이아웃이 깨지지 않음).</li><li><strong>FR-4</strong>: 메인 목록은 상위 <strong>N개(기본 6~10개)</strong> 만 노출하고, 더 보기 진입(해당 섹션 전체 목록 링크)을 제공한다.</li><li><strong>FR-5</strong>: 새 글이 추가·수정되면 빌드 시 목록에 <strong>자동 반영</strong>된다(수동 목록 편집 없음).</li><li><strong>FR-6</strong>: 요약은 frontmatter 요약 필드(<code>description</code> 등)를 <strong>우선</strong> 사용하고, 없으면 <strong>본문 앞부분 발췌</strong>로 대체하되 길이를 일정 한도로 자른다.</li></ul><h3 id="블로그-제목" tabindex="-1">블로그 제목 <a class="header-anchor" href="#블로그-제목" aria-label="Permalink to &quot;블로그 제목&quot;">​</a></h3><ul><li><strong>FR-7</strong>: 사이트 제목(브라우저 탭·헤더 표기)과 메인 hero 제목을 <strong>&quot;Agent 개발방법&quot;</strong> 으로 변경한다.</li><li><strong>FR-8</strong>: 제목 변경이 기존 내부 링크·라우팅을 깨뜨리지 않는다.</li></ul><h3 id="품질-·-보존" tabindex="-1">품질 · 보존 <a class="header-anchor" href="#품질-·-보존" aria-label="Permalink to &quot;품질 · 보존&quot;">​</a></h3><ul><li><strong>FR-9</strong>: 변경은 <strong>VitePress 빌드(strict)</strong> 를 통과한다(깨진 내부 링크 0).</li><li><strong>FR-10</strong>: 이미지가 깨진 경우(경로 없음)에도 목록 렌더링이 실패하지 않는다.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 메인 화면 첫 진입 시, 최근 글 목록이 <strong>최신순으로 정확히 정렬</strong>되어 보인다(상위 항목이 가장 최근 글).</li><li><strong>SC-2</strong>: 대표 이미지가 지정된 글은 <strong>100% 목록에 이미지와 함께</strong> 표시되고, 없는 글은 이미지 없이 정상 표시된다.</li><li><strong>SC-3</strong>: 새 글 1편 추가 후 빌드하면 <strong>수동 편집 없이</strong> 메인 목록 맨 위에 노출된다.</li><li><strong>SC-4</strong>: 사이트 제목이 모든 노출 위치에서 <strong>&quot;Agent 개발방법&quot;</strong> 으로 일관 표기된다.</li><li><strong>SC-5</strong>: 변경 후 <code>빌드(strict)</code> 가 통과하고, 기존 도달 가능 URL 회귀 0.</li><li><strong>SC-6</strong>: 메인 화면에서 최신 글 클릭까지 <strong>1클릭</strong>으로 도달한다.</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><ul><li><strong>글(Post)</strong>: 제목, 작성/생성일, 요약(또는 발췌), 대표 이미지(선택), 링크. 최신순 정렬의 단위.</li><li><strong>메인 글 목록(Home Feed)</strong>: 글의 최신순 컬렉션. 상위 N개 노출.</li><li><strong>사이트 제목(Site Title)</strong>: 브랜드 표기 문자열(&quot;Agent 개발방법&quot;).</li></ul><h2 id="assumptions" tabindex="-1">Assumptions <a class="header-anchor" href="#assumptions" aria-label="Permalink to &quot;Assumptions&quot;">​</a></h2><ul><li>&quot;주요 글&quot; 출처는 <strong>frontmatter 날짜가 있는 섹션</strong>(저널·명세 spec.md·Blog Archive)으로 한다(Clarifications 2026-06-03 + F1 정정). Cowork·Hermes·스킬 강연은 날짜가 없어 제외(날짜 추가 시 편입). 섹션별 날짜 체계가 달라 정렬 키 정규화가 필요하다.</li><li>대표 이미지는 frontmatter <strong><code>image</code> 필드 우선 + 본문 첫 이미지 폴백</strong>.</li><li>요약은 frontmatter <strong>요약 필드 우선 + 본문 발췌 폴백</strong>.</li><li>메인 목록 노출 개수 기본값은 <strong>상위 8개</strong>로 둔다(조정 가능).</li><li>&quot;블로그 제목&quot; 은 <strong>사이트 타이틀 + 메인 hero 제목</strong> 모두를 의미한다.</li><li>메인 화면의 기존 hero+6카드는 <strong>유지</strong>하고, 그 <strong>아래에 최근 글 목록</strong>을 추가한다(전면 교체 아님).</li><li>콘텐츠 파일 경로·URL 은 변경하지 않는다.</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>초기 Open Questions(주요 글 범위·이미지 출처·요약 출처·카드 배치)는 <strong>2026-06-03 Clarifications 에서 모두 해소</strong>되었다. 현재 미해결 결정 없음.</li></ul>',30)])])}const m=o(n,[["render",i]]);export{d as __pageData,m as default};
